// src/App.js
import React, { useState, useEffect, useRef } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Sample Cards ---
const bereshitCard = {
  name: "Bereshit",
  questions: [
    { question: "What day was Adam created?", answer: "The 6th day", points: 20 },
    { question: "Which day is described as 'very good'?", answer: "The 6th day", points: 20 },
    { question: "Name a story where addition becomes subtraction.", answer: "Adam added a prohibition; the serpent used this to fool Chava.", points: 20 },
  ],
};

const harHaBayitCard = {
  name: "Har HaBayit",
  questions: [
    { question: 'Which items were housed in the Kodesh ("holy") chamber?', answer: "The showbread table, menorah, and incense altar", points: 300 },
    { question: "Name an offering associated with the Omer or the Two Loaves.", answer: "Shtei Halechem (the Two Loaves) and the Omer offering are linked to Temple worship.", points: 600 },
  ],
};

const mazalCard = {
  name: "Mazal",
  text: "You had a dream of buried treasure in a far-off city... You dropped the shovel and ran home to discover the treasure buried under your own bed.",
  reward: 1000,
  rewardType: "money",
};

// --- Example Property Card ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: {
    base: 60,
    house1: 150,
    house2: 350,
    house3: 700,
    hotel: 800,
  },
  buildCost: {
    house: 200,
    hotel: 300,
  },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board events map ---
const boardEvents = {
  3: { type: "property", card: schemRoyalEstates },
  2: { type: "parsha", card: bereshitCard },
  7: { type: "mazal", card: mazalCard },
  15: { type: "har", card: harHaBayitCard },
  // add other spaces as needed
};

// --- Build 44 board positions (11 per side) ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  // Top row (left -> right)
  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });

  // Right column (top -> bottom), skip corner
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });

  // Bottom row (right -> left), skip corner
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });

  // Left column (bottom -> top), skip corner
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Component ---
function CardModal({ card, onClose, onFinish, mode }) {
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);

  if (!card) return null;

  const isProperty = mode === "property";
  const isQA = mode === "qa";

  const handleNext = () => {
    if (isQA) {
      if (currentQIndex < card.questions.length - 1) {
        setCurrentQIndex(currentQIndex + 1);
        setShowAnswer(false);
      } else {
        // Finished all questions
        const totalPoints = card.questions.reduce((sum, q) => sum + q.points, 0);
        onFinish(true, totalPoints, "zchut");
      }
    } else if (isProperty) {
      onFinish(true, 0, "zchut");
    }
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>

        {isQA && (
          <>
            <p style={{ fontWeight: "bold" }}>
              Q{currentQIndex + 1}: {card.questions[currentQIndex].question}
            </p>
            {showAnswer && <p>Answer: {card.questions[currentQIndex].answer}</p>}
            <button style={modalStyles.button} onClick={() => setShowAnswer(!showAnswer)}>
              {showAnswer ? "Hide Answer" : "Show Answer"}
            </button>
            <button style={modalStyles.button} onClick={handleNext}>
              Next Question
            </button>
          </>
        )}

        {isProperty && (
          <>
            <img
              src="/properties-red.png"
              alt={card.name}
              style={{ width: "80%", margin: "15px 0", borderRadius: 8 }}
            />
            <p>Price: ${card.price}</p>
            <p>Rent: ${card.rent.base}</p>
            <p>Houses: {card.houses}, Hotel: {card.hotel ? "Yes" : "No"}</p>
            <button style={modalStyles.button} onClick={onClose}>Close</button>
          </>
        )}
      </div>
    </div>
  );
}

